/*Table structure for table `tu_heyue` */

DROP TABLE IF EXISTS `tu_heyue`;

CREATE TABLE `tu_heyue` (
  `id` int(10) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `user_id` int(5) NOT NULL COMMENT '用户id',
  `user_name` varchar(60) DEFAULT NULL COMMENT '用户名',
  `side` enum('1','2') DEFAULT '1' COMMENT '交易类型:1=开多,2=开空',
  `symbol` varchar(20) DEFAULT 'ethusdt' COMMENT '交易对',
  `sellprice` int(3) DEFAULT '25' COMMENT '卖出价格:保证金%',
  `num` int(1) DEFAULT '0' COMMENT '运行次数',
  `oneprice` decimal(10,2) DEFAULT '60.00' COMMENT '首次价格',
  `repeatprice` decimal(10,2) DEFAULT '0.00' COMMENT '第二次梯度重复价格',
  `rangetype` int(11) DEFAULT '2' COMMENT '网格类型：1:网格差价 2:网格百分比',
  `rangeprice` double DEFAULT '0' COMMENT '网格差价',
  `rangepercent` double DEFAULT '0' COMMENT '网格加仓百分比',
  `rangeclosingpct` int(3) DEFAULT '100' COMMENT '网格平仓百分比',
  `rangeclosing` int(1) DEFAULT '1' COMMENT '网格平仓 1:不平 2：平仓',
  `risk` int(1) DEFAULT '1' COMMENT '风控：1:停用 2：开启',
  `risk_time` int(3) DEFAULT NULL COMMENT '风控时间分钟:5,15,30,60',
  `new_time` int(10) DEFAULT NULL COMMENT '更新时间',
  `newprice` double DEFAULT '0' COMMENT '最新价格',
  `status` enum('1','2') DEFAULT '1' COMMENT '状态:1=启用,2=停用',
  `closingprice` double DEFAULT '0' COMMENT '强平价格',
  `is_num` int(3) NOT NULL DEFAULT '0' COMMENT '梯度重复次数',
  `remak` varchar(200) DEFAULT NULL COMMENT '备注',
  `add_time` int(10) DEFAULT NULL COMMENT '添加时间',
  `update_time` int(10) DEFAULT NULL COMMENT '更新时间',
  `coin_id` int(5) DEFAULT NULL,
  `total` double DEFAULT '0' COMMENT '总数量',
  PRIMARY KEY (`id`),
  KEY `id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=62 DEFAULT CHARSET=utf8 COMMENT='合约任务';

/*Data for the table `tu_heyue` */

insert  into `tu_heyue`(`id`,`user_id`,`user_name`,`side`,`symbol`,`sellprice`,`num`,`oneprice`,`repeatprice`,`rangetype`,`rangeprice`,`rangepercent`,`rangeclosingpct`,`rangeclosing`,`risk`,`risk_time`,`new_time`,`newprice`,`status`,`closingprice`,`is_num`,`remak`,`add_time`,`update_time`,`coin_id`,`total`) values (60,5,'user','1','uniusdt',30,2,'30.00','20.00',2,300,100,100,1,2,30,1776509549,3.376,'2',0,2,NULL,1774061021,1783304995,NULL,0),(61,5,'user','2','uniusdt',30,2,'100.00','50.00',2,0,100,50,1,2,30,0,0,'2',0,0,NULL,1783304846,1783304846,NULL,0);

/*Table structure for table `tu_heyue_coin` */

DROP TABLE IF EXISTS `tu_heyue_coin`;

CREATE TABLE `tu_heyue_coin` (
  `id` int(5) NOT NULL AUTO_INCREMENT,
  `name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '币种',
  `symbol` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '交易对',
  `amount` double DEFAULT NULL COMMENT '交易量',
  `open` double DEFAULT NULL COMMENT '开盘价',
  `close` double DEFAULT NULL COMMENT '最新价',
  `low` double DEFAULT NULL COMMENT '最低价',
  `high` double DEFAULT NULL COMMENT '最高价',
  `vol` double DEFAULT NULL COMMENT '交易量',
  `bid` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '最高买价',
  `ask` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '最低卖价',
  `priceChange` double DEFAULT NULL COMMENT '24小时价格变动',
  `quantityprecision` int(1) DEFAULT '0' COMMENT '数量小数点位数',
  `priceprecision` int(1) DEFAULT NULL COMMENT '价格小数点位数',
  `update_time` int(10) DEFAULT NULL COMMENT '更新时间',
  `add_time` int(10) DEFAULT NULL COMMENT '添加时间',
  `weigh` int(5) DEFAULT NULL COMMENT '权重',
  `type` int(1) DEFAULT '0' COMMENT '1:u本位合约',
  `status` int(1) DEFAULT '0' COMMENT '1:显示 0:不显示',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=413 DEFAULT CHARSET=utf8;

