/*Table structure for table `tu_heyueorder` */

DROP TABLE IF EXISTS `tu_heyueorder`;

CREATE TABLE `tu_heyueorder` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `ordertype` varchar(20) DEFAULT NULL COMMENT '交易类型:1=开仓,2=平仓',
  `symbol` varchar(20) DEFAULT NULL COMMENT '交易对',
  `side` enum('1','2') DEFAULT '1' COMMENT '交易类型:1=开多,2=开空,',
  `total` decimal(10,2) DEFAULT NULL COMMENT '总金额',
  `price` decimal(10,3) DEFAULT NULL COMMENT '价格',
  `quantity` double DEFAULT NULL COMMENT '数量',
  `user_id` int(5) DEFAULT NULL,
  `username` varchar(20) DEFAULT NULL,
  `orderid` varchar(20) DEFAULT NULL COMMENT '订单号',
  `status` int(1) DEFAULT '1' COMMENT '订单状态:1=交易中,2=完成,3=未完成',
  `num` int(1) DEFAULT '0' COMMENT '交易次数',
  `log` text COMMENT '日志',
  `coin_id` int(5) DEFAULT NULL,
  `usdt` decimal(10,2) DEFAULT '0.00' COMMENT '收效',
  `add_time` int(10) DEFAULT NULL COMMENT '添加时间',
  `update_time` int(10) DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=842 DEFAULT CHARSET=utf8 COMMENT='交易记录';

