/*Table structure for table `tu_new_module` */

DROP TABLE IF EXISTS `tu_new_module`;

CREATE TABLE `tu_new_module` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) DEFAULT NULL COMMENT '模块名',
  `table_name` varchar(255) DEFAULT NULL COMMENT '表名',
  `file_name` varchar(255) DEFAULT NULL COMMENT '生成的文件名',
  `field` text COMMENT '字段列表',
  `field_text` text COMMENT '字段配置表',
  `file_number` int(11) DEFAULT NULL COMMENT '字段数量',
  `status` int(11) DEFAULT '1' COMMENT '1 未生成 2 已生成',
  `is_model` int(11) DEFAULT '0' COMMENT '是否仅生成模块  1 仅模块  0 生成全部',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `up_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `output_time` int(11) DEFAULT NULL COMMENT '输出成文件的时间',
  `is_output` int(11) DEFAULT '0' COMMENT '是否已经输出文件 1 输出 0 未输出',
  `is_output_api` int(11) DEFAULT '0' COMMENT '是否已经输出api模块文件 1 输出 0 未输出',
  `is_edit_new` int(11) DEFAULT '0' COMMENT '编辑是否新窗口打开 1 新窗口 0 弹框',
  `is_show` int(11) DEFAULT '1' COMMENT '是否隐藏  1 隐藏  0 显示',
  `table_comment` varchar(255) DEFAULT NULL COMMENT '表注释',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=32 DEFAULT CHARSET=utf8 COMMENT='根据表模型 创建curd模块关联文件';

/*Data for the table `tu_new_module` */

