/*Table structure for table `tu_order` */

DROP TABLE IF EXISTS `tu_order`;

CREATE TABLE `tu_order` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `name` varchar(100) DEFAULT NULL COMMENT '用户',
  `total` decimal(10,4) DEFAULT NULL COMMENT '金额',
  `email` varchar(200) DEFAULT NULL COMMENT '邮箱',
  `site` varchar(300) DEFAULT NULL COMMENT '域名',
  `group` varchar(100) DEFAULT NULL COMMENT '组id',
  `address` varchar(200) DEFAULT NULL COMMENT '地址',
  `phone` varchar(100) DEFAULT NULL COMMENT '电话',
  `city` varchar(100) DEFAULT NULL COMMENT '城市',
  `postcode` varchar(20) DEFAULT NULL COMMENT '邮编',
  `country` varchar(100) DEFAULT NULL COMMENT '国家',
  `purchased` varchar(30) DEFAULT NULL COMMENT '下单时间',
  `addtime` int(11) DEFAULT NULL COMMENT '增加时间',
  `status` int(11) DEFAULT '1' COMMENT '壮态  1:没支付 2:已支付',
  `orders_id` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COMMENT='交易订单';

