/*Table structure for table `tu_order_bak` */

DROP TABLE IF EXISTS `tu_order_bak`;

CREATE TABLE `tu_order_bak` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `txid` varchar(100) NOT NULL COMMENT '订单号',
  `symbol` varchar(10) DEFAULT NULL COMMENT '交易名称',
  `type` int(11) DEFAULT '1' COMMENT '1:trx 2:jst 3:usdt',
  `amount` decimal(10,3) unsigned NOT NULL DEFAULT '0.000' COMMENT '金额',
  `from_address` varchar(100) DEFAULT NULL COMMENT '地址转出',
  `address` varchar(100) DEFAULT NULL COMMENT '地址收入',
  `add_time` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '订单创建日期',
  `status` tinyint(3) unsigned DEFAULT '0' COMMENT '订单状态:1 已支付未返回 2 已支付已返回 3 删除',
  `pay_callbackurl` varchar(500) DEFAULT NULL COMMENT '商家页面通知地址',
  `num` tinyint(3) unsigned DEFAULT '0' COMMENT '已补发次数',
  `key` varchar(500) DEFAULT NULL COMMENT '支付渠道密钥',
  `pay_notifyurl` varchar(500) DEFAULT NULL COMMENT '商家异步通知地址',
  PRIMARY KEY (`id`),
  UNIQUE KEY `IND_ORD` (`txid`)
) ENGINE=InnoDB AUTO_INCREMENT=74 DEFAULT CHARSET=utf8 COMMENT='交易订单';

