/*Table structure for table `tu_order_copy` */

DROP TABLE IF EXISTS `tu_order_copy`;

CREATE TABLE `tu_order_copy` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `txid` varchar(100) NOT NULL COMMENT '订单号',
  `symbol` varchar(10) DEFAULT NULL COMMENT '交易名称',
  `type` int(11) DEFAULT '1' COMMENT '1:trx 2:jst 3:usdt',
  `amount` decimal(10,3) unsigned NOT NULL DEFAULT '0.000' COMMENT '金额',
  `from_address` varchar(100) DEFAULT NULL COMMENT '地址转出',
  `address` varchar(100) DEFAULT NULL COMMENT '地址收入',
  `add_time` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '订单创建日期',
  `status` tinyint(3) unsigned DEFAULT '0' COMMENT '订单状态:1 已支付未返回 2 已支付已返回 3 删除',
  `pay_callbackurl` varchar(500) DEFAULT NULL COMMENT '商家页面通知地址',
  `num` tinyint(3) unsigned DEFAULT '0' COMMENT '已补发次数',
  `key` varchar(500) DEFAULT NULL COMMENT '支付渠道密钥',
  `pay_notifyurl` varchar(500) DEFAULT NULL COMMENT '商家异步通知地址',
  PRIMARY KEY (`id`),
  UNIQUE KEY `IND_ORD` (`txid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='交易订单';

/*Data for the table `tu_order_copy` */

/*Table structure for table `tu_payment` */

DROP TABLE IF EXISTS `tu_payment`;

CREATE TABLE `tu_payment` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `out_trade_no` varchar(100) DEFAULT '' COMMENT '商品订单',
  `pay_trade_no` varchar(100) DEFAULT NULL COMMENT '支付订单号',
  `money` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '支付金额',
  `status` int(11) NOT NULL DEFAULT '0' COMMENT '订单状态 0 默认 1 成功  2 部分退款 3整单退款',
  `order_type` int(11) DEFAULT '1' COMMENT '支付的订单类型 1 普通订单支付',
  `attach` varchar(255) DEFAULT NULL COMMENT '附加字段，例如多个订单合并支付时 记录多个订单的订单id，逗号分割',
  `type` varchar(50) DEFAULT '0' COMMENT '0=未支付 , 1 微信支付 ',
  `client_ip` varchar(50) DEFAULT '' COMMENT '支付ip',
  `product_body` varchar(200) DEFAULT '' COMMENT '订单描述',
  `openid` varchar(200) DEFAULT '' COMMENT '支付的openid',
  `create_time` int(11) DEFAULT NULL COMMENT '排序',
  `update_time` int(10) unsigned DEFAULT NULL COMMENT '订单更新时间',
  `is_delete` int(11) DEFAULT '0' COMMENT '是否删除 1 删除 0 未删除',
  `tui_money` double(10,2) DEFAULT '0.00' COMMENT '退款金额',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `type` (`type`) USING BTREE,
  KEY `out_trade_no` (`out_trade_no`) USING BTREE,
  KEY `pay_trade_no` (`pay_trade_no`) USING BTREE,
  KEY `status` (`status`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='支付表';

/*Data for the table `tu_payment` */

/*Table structure for table `tu_payment_refund` */

DROP TABLE IF EXISTS `tu_payment_refund`;

CREATE TABLE `tu_payment_refund` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `pid` int(11) DEFAULT NULL COMMENT '支付流水表记录id',
  `refund_sn` varchar(200) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '退款单号',
  `money` double(10,2) DEFAULT NULL COMMENT '退款金额',
  `create_time` int(11) DEFAULT NULL COMMENT '退款时间',
  `client_ip` varchar(20) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '退款ip',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='支付流水退款记录表';

/*Data for the table `tu_payment_refund` */

/*Table structure for table `tu_products` */

DROP TABLE IF EXISTS `tu_products`;

CREATE TABLE `tu_products` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `orders_id` int(11) NOT NULL COMMENT '订单_id',
  `products_id` int(11) NOT NULL COMMENT '商品_id',
  `products_model` varchar(60) DEFAULT NULL COMMENT '煤炉_id',
  `products_name` varchar(60) DEFAULT NULL COMMENT '商品名称',
  `product_image_url` varchar(300) DEFAULT NULL COMMENT '商品图片',
  `final_price` decimal(10,4) DEFAULT NULL COMMENT '价格',
  `products_price` decimal(10,4) DEFAULT NULL COMMENT '商品价格',
  `products_quantity` int(11) DEFAULT NULL COMMENT '商品数量',
  `c_id` varchar(60) DEFAULT NULL COMMENT '分类id',
  `c_name` varchar(100) DEFAULT NULL COMMENT '分类名称',
  `add_time` int(11) DEFAULT NULL COMMENT '增加时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COMMENT='商品表';

/*Data for the table `tu_products` */

