/*Table structure for table `tu_shell_min` */

DROP TABLE IF EXISTS `tu_shell_min`;

CREATE TABLE `tu_shell_min` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `shell_id` int(10) DEFAULT NULL COMMENT 'shell_id',
  `url` varchar(500) DEFAULT NULL COMMENT 'url',
  `addtime` int(10) DEFAULT NULL COMMENT '增加时间',
  `status` int(1) DEFAULT '1' COMMENT '1:正常2：停用',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=350 DEFAULT CHARSET=utf8mb4 COMMENT='大码';

