/*Table structure for table `tu_upload_files` */

DROP TABLE IF EXISTS `tu_upload_files`;

CREATE TABLE `tu_upload_files` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `storage` tinyint(1) DEFAULT '0' COMMENT '存储位置 0本地',
  `app` smallint(6) DEFAULT '0' COMMENT '来自应用 0前台 1后台',
  `user_id` int(11) NOT NULL DEFAULT '0' COMMENT '根据app类型判断用户类型',
  `file_name` varchar(100) DEFAULT '',
  `file_size` int(11) DEFAULT '0',
  `extension` varchar(10) DEFAULT '' COMMENT '文件后缀',
  `url` varchar(500) DEFAULT '' COMMENT '图片路径',
  `create_time` int(11) DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=341 DEFAULT CHARSET=utf8;

/*Data for the table `tu_upload_files` */

insert  into `tu_upload_files`(`id`,`storage`,`app`,`user_id`,`file_name`,`file_size`,`extension`,`url`,`create_time`) values (340,0,1,1,'trx.png',3998,'png','/uploads/file/20241114/6cac6c24901ddaf5e7e80090f3d120f9.png',1731571592);

/*Table structure for table `tu_usdt` */

DROP TABLE IF EXISTS `tu_usdt`;

CREATE TABLE `tu_usdt` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `type` enum('1','2','3') DEFAULT '1' COMMENT '1:冲值2:提现3：奖励',
  `user_id` int(10) DEFAULT NULL,
  `coin_code` varchar(20) DEFAULT NULL COMMENT '币种',
  `received_amount` decimal(10,2) DEFAULT '0.00' COMMENT '接收金额',
  `address` varchar(60) DEFAULT NULL COMMENT '接收地址',
  `from` varchar(60) DEFAULT NULL COMMENT '发送地址',
  `status` enum('1','2','3') DEFAULT '1' COMMENT '1:支付中2:成功3:审核中',
  `addtime` int(10) DEFAULT NULL,
  `updatetime` int(10) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COMMENT='冲提日志';

/*Data for the table `tu_usdt` */

/*Table structure for table `tu_user` */

DROP TABLE IF EXISTS `tu_user`;

CREATE TABLE `tu_user` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `username` varchar(180) NOT NULL,
  `password` varbinary(255) DEFAULT NULL,
  `mobile` varchar(20) DEFAULT NULL,
  `eamil` varchar(100) DEFAULT NULL,
  `margin` float DEFAULT '1' COMMENT '保证金比例%',
  `token` varchar(50) DEFAULT NULL,
  `money` decimal(10,2) DEFAULT '0.00',
  `status` int(1) DEFAULT '1' COMMENT '1:正常 2：使用',
  `updatetime` int(10) DEFAULT NULL,
  `usdt` decimal(10,6) DEFAULT NULL,
  `addtime` int(10) DEFAULT NULL,
  `admin` tinyint(1) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  `codes` char(100) DEFAULT NULL COMMENT '邀请码',
  `bnaccess` varchar(100) DEFAULT NULL,
  `bnasecret` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uix_users_id` (`id`),
  UNIQUE KEY `uix_users_name` (`username`),
  KEY `idx_users_deleted_at` (`deleted_at`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8;

/*Data for the table `tu_user` */

